// Note: total_nrows is the full tensor row count (ne01), nrows is the slice size (row_diff)
//       row_low is the starting row offset for this slice (for split tensor support)
static void reorder_mul_mat_vec_q4_k_q8_1_sycl(const void *    vx,
                                               const void *    vy,
                                               float *         dst,
                                               const int       ncols,
                                               const int       nrows,
                                               const int       total_nrows,
                                               const int       row_low,
                                               dpct::queue_ptr stream,
                                               const float *   fused_add          = nullptr,
                                               const int64_t   fused_add_ne0      = 0,
                                               const int64_t   fused_add_nb0      = sizeof(float),
                                               const int64_t   fused_add_row_base = 0) {
    GGML_ASSERT(ncols % QK_K == 0);

    const int        block_num_y   = ceil_div(nrows, GGML_SYCL_MMV_Y);
    constexpr size_t num_subgroups = 16;

    const sycl::range<3> global_size(1, GGML_SYCL_MMV_Y, block_num_y * WARP_SIZE);
    const sycl::range<3> workgroup_size(1, GGML_SYCL_MMV_Y, num_subgroups * WARP_SIZE);

    stream->submit([&](sycl::handler & cgh) {
        cgh.parallel_for<mmvq_reorder_kernel_name<GGML_TYPE_Q4_K>>(
            sycl::nd_range<3>(global_size, workgroup_size),
            [=](sycl::nd_item<3> nd_item) [[sycl::reqd_sub_group_size(WARP_SIZE)]] {
                mul_mat_vec_q_reorder<reorder_vec_dot_q_sycl<GGML_TYPE_Q4_K>>(
                    vx, vy, dst, ncols, nrows, total_nrows, row_low, nd_item, fused_add, fused_add_ne0, fused_add_nb0,
                    fused_add_row_base);
            });
    });
}

